// ══════════════════════════════════════════════════════
// NODE 02 · PFLICHTFELDER VALIDIEREN
// Prüft ob alle Pflichtfelder vorhanden und plausibel sind
// ══════════════════════════════════════════════════════

const body = $input.first().json.body || $input.first().json;
const errors = [];
const warnings = [];

// Pflichtfelder
const required = {
  typ: 'Objekttyp',
  angebot: 'Angebotstyp',
  adresse: 'Adresse',
  flaeche: 'Wohnfläche',
  zimmer: 'Zimmer',
  preis: 'Preis',
  zustand: 'Zustand'
};

for (const [key, label] of Object.entries(required)) {
  if (!body[key] || String(body[key]).trim() === '') {
    errors.push(`Pflichtfeld fehlt: ${label}`);
  }
}

// Fläche plausibel?
if (body.flaeche) {
  const fl = parseFloat(body.flaeche);
  if (fl < 10) errors.push('Wohnfläche zu klein (min. 10 m²)');
  if (fl > 5000) warnings.push('Wohnfläche sehr gross — bitte prüfen');
}

// Preis plausibel?
if (body.preis) {
  const p = parseInt(String(body.preis).replace(/[^0-9]/g,''));
  if (p < 100) errors.push('Preis zu niedrig — CHF-Betrag eingeben');
  if (body.angebot === 'Verkauf' && p < 50000) warnings.push('Kaufpreis unter CHF 50.000 — bitte prüfen');
  if (body.angebot === 'Vermietung' && p > 50000) warnings.push('Mietpreis über CHF 50.000 — bitte prüfen');
}

// Zimmeranzahl
if (body.zimmer) {
  const zm = parseFloat(body.zimmer);
  if (zm > 20) warnings.push('Zimmeranzahl über 20 — bitte prüfen');
}

// Baujahr
if (body.baujahr) {
  const bj = parseInt(body.baujahr);
  if (bj < 1800 || bj > 2030) errors.push('Baujahr ungültig (1800–2030)');
}

if (errors.length > 0) {
  return [{ json: {
    _error: true,
    step: 'Eingabe-Validierung',
    error: errors.join(' | '),
    warnings
  }}];
}

return [{ json: {
  _error: false,
  body,
  warnings,
  validatedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 03 · BILDER VALIDIEREN
// Prüft Anzahl, Typ, Grösse und Base64-Integrität
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const body = input.body;
const bilder = Array.isArray(body.bilder) ? body.bilder : [];
const errors = [];
const warnings = [];
const validBilder = [];

const MAX_BILDER = 10;
const VALID_TYPES = ['image/jpeg', 'image/png', 'image/webp'];

// Anzahl
if (bilder.length === 0) {
  warnings.push('Keine Bilder hochgeladen — Exposé ohne Bildbeschreibungen');
}
if (bilder.length > MAX_BILDER) {
  warnings.push(`Nur die ersten ${MAX_BILDER} Bilder werden verarbeitet`);
}

// Jedes Bild prüfen
for (let i = 0; i < Math.min(bilder.length, MAX_BILDER); i++) {
  const b = bilder[i];
  const bErrors = [];

  // Typ prüfen
  if (!b.type || !VALID_TYPES.includes(b.type)) {
    bErrors.push(`Ungültiger Bildtyp: ${b.type || 'unbekannt'}`);
  }

  // Base64 vorhanden?
  if (!b.data || b.data.length < 100) {
    bErrors.push('Bilddaten fehlen oder zu klein');
  }

  // Base64 Syntax prüfen
  if (b.data) {
    const validB64 = /^[A-Za-z0-9+/]+=*$/.test(b.data.replace(/\s/g,''));
    if (!validB64) bErrors.push('Base64-Daten beschädigt');
  }

  // Geschätzte Grösse (Base64 → Bytes)
  if (b.data) {
    const estBytes = Math.round(b.data.length * 0.75);
    const estMB = (estBytes / 1024 / 1024).toFixed(1);
    if (estBytes > 5 * 1024 * 1024) {
      bErrors.push(`Bild ${i+1} zu gross (ca. ${estMB} MB)`);
    }
  }

  if (bErrors.length > 0) {
    errors.push(...bErrors);
  } else {
    validBilder.push({
      ...b,
      index: i,
      label: b.label || (i === 0 ? 'Hauptbild' : `Bild ${i+1}`),
      mediaType: b.type
    });
  }
}

if (errors.length > 0) {
  return [{ json: {
    _error: true,
    step: 'Bild-Validierung',
    error: errors.join(' | '),
    warnings
  }}];
}

return [{ json: {
  ...input,
  validBilder,
  bildAnzahl: validBilder.length,
  bildWarnings: warnings,
  bilderValidatedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 04 · DATEN ANREICHERN
// Normalisiert, formatiert und ergänzt alle Felder
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const body = input.body;

// Preis formatieren
const preisRaw = parseInt(String(body.preis).replace(/[^0-9]/g,''));
const preisFormatiert = new Intl.NumberFormat('de-CH').format(preisRaw);
const preisLabel = body.angebot === 'Vermietung' ? 'Mietzins' : 'Kaufpreis';

// Zimmer-Label
const zimmerLabel = body.zimmer === '6+' ? '6 und mehr Zimmer' : `${body.zimmer}-Zimmer`;

// Adresse aufbereiten
const adresseParts = String(body.adresse).split(',').map(s => s.trim());
const strasseNr = adresseParts[0] || body.adresse;
const ortPLZ = adresseParts.slice(1).join(', ');

// Kanton-Vollname
const kantone = {
  ZH:'Zürich',ZG:'Zug',BS:'Basel-Stadt',GE:'Genf',BE:'Bern',
  LU:'Luzern',AG:'Aargau',SZ:'Schwyz',NW:'Nidwalden',OW:'Obwalden',
  UR:'Uri',GL:'Glarus',AR:'Appenzell Ausserrhoden',AI:'Appenzell Innerrhoden',
  SG:'St. Gallen',GR:'Graubünden',TG:'Thurgau',SH:'Schaffhausen',
  TI:'Tessin',VD:'Waadt',VS:'Wallis',FR:'Freiburg',NE:'Neuenburg',
  JU:'Jura',SO:'Solothurn',BL:'Basel-Landschaft'
};
const kantonName = kantone[body.kanton] || body.kanton || '';

// Merkmale aufbereiten
const merkmale = Array.isArray(body.merkmale) ? body.merkmale : [];
const merkmaleTxt = merkmale.length > 0 ? merkmale.join(', ') : 'keine besonderen Merkmale angegeben';

// Alter berechnen
let objektAlter = '';
if (body.baujahr) {
  const alter = 2025 - parseInt(body.baujahr);
  objektAlter = alter <= 0 ? 'Neubau' : alter <= 5 ? 'nahezu neu' : `${alter} Jahre alt`;
}

// Renovations-Info
let renovationsInfo = '';
if (body.renovation && body.baujahr) {
  const jahreSeitReno = 2025 - parseInt(body.renovation);
  renovationsInfo = jahreSeitReno === 0 ? 'frisch renoviert' :
    jahreSeitReno <= 3 ? 'kürzlich renoviert' :
    jahreSeitReno <= 10 ? `vor ${jahreSeitReno} Jahren renoviert` :
    `Renovation ${body.renovation}`;
}

return [{ json: {
  ...input,
  enriched: {
    preisRaw, preisFormatiert, preisLabel,
    zimmerLabel, strasseNr, ortPLZ, kantonName,
    merkmaleTxt, objektAlter, renovationsInfo,
    adresseVoll: `${body.adresse}${kantonName ? ', ' + kantonName : ''}`
  },
  enrichedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 05 · SYSTEM PROMPT AUFBAUEN
// Personalisiert den System Prompt für dieses Objekt
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const body = input.body;
const e = input.enriched;

// Stil-Anweisungen je nach Ton
const stilAnweisung = {
  'Professionell': 'Sachlich, präzise, seriös. Fakten stehen im Vordergrund. Keine Superlative.',
  'Emotional': 'Wärmend, einladend, Gefühle ansprechen. Lässt den Leser sich vorstellen, dort zu wohnen.',
  'Premium': 'Exklusiv, distinguiert, zurückhaltend luxuriös. Für anspruchsvolle Käufer.',
  'Familiär': 'Herzlich, einladend, praktisch orientiert. Alltag und Zusammenleben betonen.'
};
const stil = stilAnweisung[body.ton] || stilAnweisung['Professionell'];

// Zielgruppen-Fokus
const zielgruppenFokus = {
  'Familien': 'Betone Schulen, Garten, Kinderzimmer, Sicherheit, Gemeinschaft.',
  'Paare / Singles': 'Betone Lage, Lifestyle, moderne Küche, Erreichbarkeit, Ausgehen.',
  'Investoren': 'Betone Rendite-Potenzial, Lage-Entwicklung, Mietpreise, Substanz.',
  'Keine Vorgabe': 'Keine spezifische Zielgruppe — breite Ansprache.'
};
const zielFokus = zielgruppenFokus[body.zielgruppe] || zielgruppenFokus['Keine Vorgabe'];

const systemPrompt = `Du bist der beste Immobilien-Texter der Schweiz.
Du hast 20 Jahre Erfahrung und hast schon tausende Exposés für Liegenschaften im Wert von über 2 Milliarden CHF geschrieben.

DEINE GRUNDSÄTZE:
- Nur Schweizer Hochdeutsch
- Keine Klischees («einzigartiges Schmuckstück», «traumhafte Lage»)
- Keine leeren Versprechen
- Keine Adjektiv-Stapelungen
- Bilder präzise analysieren, Details natürlich einweben
- Jeder Satz muss einen Mehrwert liefern

STIL FÜR DIESES EXPOSÉ: ${stil}
ZIELGRUPPE: ${zielFokus}

OBJEKT-KONTEXT:
- ${e.zimmerLabel}-${body.typ} in ${e.adresseVoll}
- ${body.angebot} für CHF ${e.preisFormatiert}
- ${body.flaeche} m² | ${body.zustand}
${e.objektAlter ? `- Alter: ${e.objektAlter}` : ''}
${e.renovationsInfo ? `- Renovation: ${e.renovationsInfo}` : ''}

AUFBAU VOLLSTÄNDIGES EXPOSÉ (500–700 Wörter):
1. Emotionaler Einstieg (2–3 Sätze) — Stimmung, nicht Fakten
2. Objekt-Beschreibung — Räume, Flächen, Qualität
3. Ausstattung & Merkmale — präzise, keine Listen
4. Lage & Umgebung — konkret, mit Distanzen
5. Abschluss — subtiler Call-to-Action

AUFBAU PORTAL-VERSION (max. 1800 Zeichen):
- Erste Zeile: Kerninfo (Typ, Zimmer, Fläche, Ort)
- Dann: 3–4 kurze Absätze
- Alle Pflichtinfos: Fläche, Zimmer, Preis, Lage
- Kein Fülltext, jedes Wort zählt

Gib exakt diese zwei Blöcke aus:
===VOLLSTAENDIG===
[500-700 Wörter]
===PORTAL===
[max. 1800 Zeichen]`;

return [{ json: {
  ...input,
  systemPrompt,
  systemPromptBuiltAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 06 · USER PROMPT AUFBAUEN
// Baut den detaillierten Objekt-Prompt für Claude
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const body = input.body;
const e = input.enriched;
const bilder = input.validBilder || [];

// Bild-Labels für Prompt
const bildInfo = bilder.length > 0
  ? `${bilder.length} Bild${bilder.length > 1 ? 'er' : ''} beigefügt:\n` +
    bilder.map((b,i) => `  · Bild ${i+1}: ${b.label}`).join('\n')
  : 'Keine Bilder vorhanden — Exposé ohne Bildreferenzen erstellen';

// Preis-Info
const nkInfo = body.nk
  ? `CHF ${Number(String(body.nk).replace(/[^0-9]/g,'')).toLocaleString('de-CH')} / Monat Nebenkosten`
  : 'nicht angegeben';

const userPrompt = `AUFGABE: Professionelles Immobilien-Exposé erstellen

═══ OBJEKT-GRUNDDATEN ═══
Typ:              ${body.typ}
Angebotsart:      ${body.angebot}
Adresse:          ${e.adresseVoll}
Wohnfläche:       ${body.flaeche} m²
Anzahl Zimmer:    ${body.zimmer}
Stockwerk:        ${body.stockwerk || 'nicht angegeben'}
Baujahr:          ${body.baujahr || 'nicht angegeben'}${e.objektAlter ? ' (' + e.objektAlter + ')' : ''}
Letzte Renovation:${body.renovation || 'nicht angegeben'}${e.renovationsInfo ? ' (' + e.renovationsInfo + ')' : ''}
${e.preisLabel}: CHF ${e.preisFormatiert}
Nebenkosten:      ${nkInfo}

═══ AUSSTATTUNG & ZUSTAND ═══
Zustand:          ${body.zustand}
Heizungsart:      ${body.heizung || 'nicht angegeben'}
Parkierung:       ${body.parkierung || 'keine'}
Merkmale:         ${e.merkmaleTxt}
Weitere Details:  ${body.weiteres || 'keine zusätzlichen Angaben'}

═══ LAGE & INFRASTRUKTUR ═══
Umgebung/Quartier:${body.umgebung || 'nicht angegeben'}
Öffentlicher Verkehr: ${body.oev || 'nicht angegeben'}
Einkauf & Schulen:${body.schule || 'nicht angegeben'}

═══ BILDER ═══
${bildInfo}

═══ AUSGABE-VORGABEN ═══
Ton:              ${body.ton || 'Professionell'}
Zielgruppe:       ${body.zielgruppe || 'Keine Vorgabe'}

Bitte analysiere zuerst die beigefügten Bilder und integriere konkrete visuelle Details natürlich in beide Texte.
Dann erstelle die zwei Versionen exakt wie im System Prompt vorgegeben.`;

return [{ json: {
  ...input,
  userPrompt,
  userPromptBuiltAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 07 · CLAUDE MESSAGE BAUEN
// Kombiniert Bilder + Text zu Claude API Format
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const bilder = input.validBilder || [];
const userPrompt = input.userPrompt;

// Content-Array: Bilder zuerst, dann Text
const content = [];

// Bilder als Vision-Blocks
for (const bild of bilder) {
  // Bild-Block
  content.push({
    type: 'image',
    source: {
      type: 'base64',
      media_type: bild.mediaType || 'image/jpeg',
      data: bild.data
    }
  });
  // Label direkt nach Bild
  content.push({
    type: 'text',
    text: `↑ ${bild.label} (Bild ${bild.index + 1} von ${bilder.length})`
  });
}

// Haupt-Prompt
content.push({ type: 'text', text: userPrompt });

// API Body
const apiBody = {
  model: 'claude-sonnet-4-6',
  max_tokens: 3000,
  system: input.systemPrompt,
  messages: [{ role: 'user', content }]
};

return [{ json: {
  ...input,
  apiBody,
  messageBuiltAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 09 · API ANTWORT PRÜFEN
// Prüft ob Claude geantwortet hat und extrahiert Text
// ══════════════════════════════════════════════════════

const claudeResp = $input.first().json;

// HTTP-Fehler
if (claudeResp.error) {
  const code = claudeResp.error.type || 'unknown';
  const msg = claudeResp.error.message || 'Unbekannter API-Fehler';
  const deutlich = {
    'authentication_error': 'Ungültiger API Key. Bitte CLAUDE_API_KEY in n8n prüfen.',
    'permission_error': 'Keine Berechtigung. API Key hat keine Zugriffsberechtigung.',
    'rate_limit_error': 'API Rate Limit erreicht. Bitte 1 Minute warten und erneut versuchen.',
    'overloaded_error': 'Claude ist überlastet. Bitte in 30 Sekunden erneut versuchen.'
  };
  return [{ json: {
    _error: true,
    step: 'Claude API',
    error: deutlich[code] || `API Fehler: ${msg}`
  }}];
}

// Antwort-Text
let rawText = '';
try {
  rawText = claudeResp.content?.[0]?.text || '';
} catch(e) {
  return [{ json: { _error: true, step: 'API Antwort', error: 'Antwort-Format unbekannt' }}];
}

if (!rawText || rawText.length < 100) {
  return [{ json: { _error: true, step: 'API Antwort', error: 'Claude hat keinen verwertbaren Text zurückgegeben' }}];
}

return [{ json: {
  rawText,
  usage: claudeResp.usage || {},
  model: claudeResp.model || 'claude-sonnet-4-6',
  apiCheckedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 10 · VERSIONEN EXTRAHIEREN
// Parst ===VOLLSTAENDIG=== und ===PORTAL=== aus dem Text
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const raw = input.rawText;

function extract(text, startMarker, endMarker) {
  const si = text.indexOf(startMarker);
  if (si === -1) return null;
  const after = text.slice(si + startMarker.length);
  if (!endMarker) return after.trim();
  const ei = after.indexOf(endMarker);
  return ei === -1 ? after.trim() : after.slice(0, ei).trim();
}

let vollstaendig = extract(raw, '===VOLLSTAENDIG===', '===PORTAL===');
let portal = extract(raw, '===PORTAL===', null);

// Fallback: Varianten des Markers
if (!vollstaendig) {
  vollstaendig = extract(raw, '=== VOLLSTÄNDIGES EXPOSÉ ===', '=== PORTAL') ||
                 extract(raw, 'VOLLSTÄNDIGES EXPOSÉ', 'PORTAL');
}
if (!portal) {
  portal = extract(raw, 'PORTAL-VERSION', null) ||
            extract(raw, 'PORTAL VERSION', null);
}

// Letzter Fallback: ganzer Text
if (!vollstaendig && !portal) {
  vollstaendig = raw.trim();
  portal = raw.trim();
}

if (!vollstaendig) vollstaendig = raw.trim();
if (!portal) portal = vollstaendig.slice(0, 1800);

return [{ json: {
  ...input,
  vollstaendig,
  portal,
  extractedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 11 · VOLLSTÄNDIGES EXPOSÉ PRÜFEN
// Wortanzahl, Struktur, Qualitäts-Check
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const text = input.vollstaendig;
const warnings = [];

// Wortanzahl
const worte = text.trim().split(/\s+/).filter(w => w.length > 0).length;
const zeichen = text.length;

// Zu kurz?
if (worte < 200) warnings.push(`Vollständiges Exposé sehr kurz (${worte} Wörter, Ziel: 500–700)`);
if (worte > 900) warnings.push(`Vollständiges Exposé sehr lang (${worte} Wörter, Ziel: 500–700)`);

// Verbotene Klischees prüfen
const klischees = [
  'einzigartiges Schmuckstück', 'Traumlage', 'traumhaft', 'einzigartig',
  'unverbaubar', 'absolut ruhig', 'perfekt gelegen', 'ideale Lage'
];
const gefundeneKlischees = klischees.filter(k => text.toLowerCase().includes(k.toLowerCase()));
if (gefundeneKlischees.length > 0) {
  warnings.push(`Klischee-Begriffe gefunden: ${gefundeneKlischees.join(', ')}`);
}

// Pflicht-Infos vorhanden?
const checkPflicht = (field, label) => {
  if (!text.toLowerCase().includes(field.toLowerCase())) {
    warnings.push(`«${label}» nicht im Exposé erwähnt`);
  }
};

// Prüfe ob Ort erwähnt
// (nur warnen, nicht abbrechen)

return [{ json: {
  ...input,
  qcVollstaendig: {
    worte,
    zeichen,
    warnings,
    ok: warnings.length === 0
  },
  qcVollstaendigAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 12 · PORTAL-VERSION PRÜFEN
// Zeichenlimit, Pflichtfelder, Struktur
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

let portal = input.portal;
const warnings = [];
let trimmed = false;

// Zeichenlimit 1800 hart durchsetzen
if (portal.length > 1800) {
  // Sauber auf Satzende schneiden
  let cut = portal.slice(0, 1780);
  const lastDot = Math.max(
    cut.lastIndexOf('.'),
    cut.lastIndexOf('!'),
    cut.lastIndexOf('?')
  );
  portal = lastDot > 1600 ? cut.slice(0, lastDot + 1) : cut.trim() + '...';
  trimmed = true;
  warnings.push(`Portal-Version wurde auf ${portal.length} Zeichen gekürzt`);
}

// Zu kurz?
if (portal.length < 300) {
  warnings.push(`Portal-Version sehr kurz (${portal.length} Zeichen)`);
}

// Prüfe Pflicht-Angaben für Portale
const pflicht = [
  ['m²', 'Fläche in m²'],
  ['CHF', 'Preis in CHF'],
];
for (const [term, label] of pflicht) {
  if (!portal.includes(term)) {
    warnings.push(`${label} fehlt in Portal-Version`);
  }
}

return [{ json: {
  ...input,
  portal,
  qcPortal: {
    zeichen: portal.length,
    limit: 1800,
    trimmed,
    warnings,
    ok: !trimmed && warnings.length === 0
  },
  qcPortalAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 13 · ERGEBNISSE ZUSAMMENFÜHREN
// Wartet auf beide QC-Nodes und fügt zusammen
// ══════════════════════════════════════════════════════

// Wir nehmen hier einfach den letzten Input (sequentiell)
const input = $input.first().json;
if (input._error) return [{ json: input }];

// Alle Warnings sammeln
const allWarnings = [
  ...(input.warnings || []),
  ...(input.bildWarnings || []),
  ...(input.qcVollstaendig?.warnings || []),
  ...(input.qcPortal?.warnings || [])
].filter(Boolean);

return [{ json: {
  ...input,
  allWarnings,
  mergedAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 14 · FINAL QC — GESAMTPRÜFUNG
// Letzter Check bevor die Antwort gesendet wird
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const v = input.vollstaendig || '';
const p = input.portal || '';
const body = input.body || {};
const e = input.enriched || {};
const criticalErrors = [];

// Vollständiges Exposé nicht leer
if (v.length < 50) criticalErrors.push('Vollständiges Exposé fehlt oder zu kurz');

// Portal nicht leer
if (p.length < 50) criticalErrors.push('Portal-Version fehlt oder zu kurz');

// Portal-Limit
if (p.length > 1800) criticalErrors.push(`Portal überschreitet Zeichenlimit (${p.length}/1800)`);

// Adresse im Vollexposé vorhanden?
const ortParts = (body.adresse || '').split(',').map(s => s.trim());
const ortGefunden = ortParts.some(part => part.length > 2 && v.includes(part));
if (!ortGefunden && body.adresse) {
  // Kein kritischer Fehler, nur Hinweis
}

if (criticalErrors.length > 0) {
  return [{ json: {
    _error: true,
    step: 'Final QC',
    error: criticalErrors.join(' | ')
  }}];
}

return [{ json: {
  ...input,
  finalQcPassed: true,
  finalQcAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 15 · RESPONSE FORMATIEREN
// Baut die finale JSON-Antwort für das HTML-Tool
// ══════════════════════════════════════════════════════

const input = $input.first().json;
if (input._error) return [{ json: input }];

const e = input.enriched || {};
const body = input.body || {};

// Objekt-Zusammenfassung
const zusammenfassung = [
  body.zimmer ? `${body.zimmer}-Zimmer-${body.typ}` : body.typ,
  body.flaeche ? `${body.flaeche} m²` : null,
  e.adresseVoll || body.adresse,
  e.preisFormatiert ? `CHF ${e.preisFormatiert}` : null
].filter(Boolean).join(' · ');

return [{ json: {
  success: true,
  vollstaendig: input.vollstaendig,
  portal: input.portal,
  meta: {
    zusammenfassung,
    bildAnzahl: input.bildAnzahl || 0,
    worteVollstaendig: input.qcVollstaendig?.worte || 0,
    zeichenVollstaendig: input.qcVollstaendig?.zeichen || 0,
    zeichenPortal: input.qcPortal?.zeichen || 0,
    model: input.model || 'claude-sonnet-4-6',
    tokensUsed: input.usage?.output_tokens || 0,
    generatedAt: new Date().toISOString()
  },
  warnings: input.allWarnings || []
}}];

// ══════════════════════════════════════════════════════
// NODE 17 · FEHLER-HANDLER (Claude API)
// Fängt HTTP-Fehler vom API-Call ab
// ══════════════════════════════════════════════════════

const err = $input.first().json;
const errMsg = err?.message || err?.error?.message || JSON.stringify(err).slice(0,200);

const userMessages = {
  '401': 'Ungültiger API Key. Bitte CLAUDE_API_KEY in n8n > Settings > Environment Variables prüfen.',
  '403': 'Zugriff verweigert. API Key hat keine Berechtigungen.',
  '429': 'Zu viele Anfragen. Bitte 60 Sekunden warten und erneut versuchen.',
  '529': 'Claude API überlastet. Bitte 30 Sekunden warten.',
  '500': 'Claude API interner Fehler. Bitte erneut versuchen.',
  '503': 'Claude API vorübergehend nicht erreichbar.'
};

const code = String(err?.statusCode || '');
const message = userMessages[code] || `Verbindungsfehler zur Claude API: ${errMsg}`;

return [{ json: {
  success: false,
  error: message,
  errorCode: code,
  errorAt: new Date().toISOString()
}}];

// ══════════════════════════════════════════════════════
// NODE 18 · FEHLER-RESPONSE
// Sendet Fehlermeldung auf Deutsch zurück ans Tool
// ══════════════════════════════════════════════════════

const input = $input.first().json;

// Fehler-Objekte normalisieren
const errorMsg = input.error || input._error && 'Unbekannter Fehler' || 'Fehler';
const step = input.step || 'Verarbeitung';

return [{ json: {
  success: false,
  error: typeof errorMsg === 'string' ? errorMsg : JSON.stringify(errorMsg),
  step,
  errorAt: new Date().toISOString()
}}];
